sql:
SELECT * 
FROM study_participants
WHERE study_id = 0;

SELECT group_id, percentage, relative_risk
FROM response_details
WHERE response_id = 1;

SELECT group_name, group_description, group_code
FROM child_groups
WHERE group_code LIKE 'S%';

SELECT user_id, user_name
FROM users
WHERE user_id NOT IN (
    SELECT created_by 
    FROM surveys
);

SELECT questions.question_text, responses.response_text
FROM questions
JOIN responses ON questions.question_id = responses.question_id;

SELECT study_id, COUNT(outcome_id) AS total_outcomes
FROM study_outcomes
GROUP BY study_id;

external_knowledge:
- 'Researcher' refers to users with the role of researcher;
- 'Published' surveys are those with the status 'published';
- 'Survey date' indicates when the survey was conducted;
- The access type represents the type of access to the survey, such as 'view' or 'download'.
